#include <stdio.h>
int main() {
    int T, N, Y, cur, x;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &Y);
        cur = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &x);
            cur |= x;
        }
        if (cur & ~Y) {
            printf("-1\n");
        } else {
            printf("%d\n", Y & ~cur);
        }
    }
    return 0;
}

