import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        Y = int(next(it))
        cur = 0
        for _ in range(N):
            cur |= int(next(it))
        if cur & (~Y):
            out.append('-1')
        else:
            out.append(str(Y & (~cur)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

